function a(){const t=new Date;return`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,"0")}`}function o(t){if(!t)return"";const[r,e]=t.split("-");return`${["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"][parseInt(e)-1]}-${r}`}function s(t=new Date().getFullYear()){const r=[];for(let e=0;e<12;e++){const n=`${t}-${String(e+1).padStart(2,"0")}`;r.push({value:n,display:o(n)})}return r.reverse()}export{s as a,o as f,a as g};
